var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"오래 기다리셨습니다. 시니어님.","JPN":"お待たせいたしました。シニア。","ENG":"Thank you for your patience, Senior.","TWN":"您久等了，Senior。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"전용기를 준비해 두었습니다. 이제 샤레이드로 복귀하시죠.","JPN":"専用機を用意しました。シャレードに復帰してください。","ENG":"We have already prepared a private plane for you. It's time you returned to Charade.","TWN":"專機已經備妥，我們回查雷德去吧。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"부재중이신 동안, 그라운드 원 관리자에게서 연락이 왔습니다.","JPN":"ご不在の間、グラウンド・ワンの管理者から連絡がありました。","ENG":"While you were away, you were contacted by Ground One's Administrator.","TWN":"您不在的這段時間，G1的管理者有來電。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"어떻게 할까요?","JPN":"どうしましょうか？","ENG":"What would you like to do?","TWN":"該怎麼做呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"르네가? 연결해주게.","JPN":"ルネが？　繋げてくれ。","ENG":"Renée called? Connect her through.","TWN":"芮妮嗎？幫我接通。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자 회의 뒤로 오랜만이네, 리하르트.","JPN":"最高管理者会議以来だな、リヒャルト。","ENG":"Long time no see, Richard. Last time we saw each other was back during the Supreme Administrator meeting, wasn't it?","TWN":"自從最高管理者會議結束後，我們多久沒見啦，理查。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"기껏 샤레이드까지 왔는데, 얼굴 한 번 안 비추는 건 너무 실례 아니야?","JPN":"せっかくシャレードまで来たのに、顔も見せてくれないなんて冷たいんじゃないか？","ENG":"Don't you think it's rude to not even show your face when I've come all this way to Charade?","TWN":"我好不容易才來一趟查雷德，你好歹也露個臉，這麼不給面子？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그러는 너는 이런 시기에 꽤 한가해 보이는군.","JPN":"そういう君はこんな時期なのに随分と暇そうだな。","ENG":"Well, it seems you're quite free in these busy times.","TWN":"你還有時間跟我說這些，看來你蠻閒的嘛？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"지난 회의에서도 그라운드 원은 조용할 날이 없다고 불평하지 않았나?","JPN":"前回の会議でもグラウンド・ワンは毎日事件だらけだと文句を言っていなかったか？","ENG":"Didn't you complain last time during the meeting about how not a day goes by without trouble at Ground One?","TWN":"我記得在上次會議中你不是還抱怨，說什麼G1沒一天是安寧的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"네가 소임을 다하지 않으면 다른 직원들 기강도 해이해질 수밖에 없다.","JPN":"君がしっかりしなければ、他の社員も気が緩むものだ。","ENG":"Just know that your employees will slack off if you do not do your duties.","TWN":"你這樣不善盡職責的話，也不能怪底下的人紀律渙散吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"흥, 고리타분한 건 여전하네.","JPN":"ふん、相変わらず頭が硬いな。","ENG":"Hmph. I see you haven't changed at all.","TWN":"哼，你講話還是一樣喜歡話中帶刺。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"보고서 봤어. 이번에 그 미친 테러리스트의 신병을 확보했다면서?","JPN":"報告書は読んだ。あのイカれたテロリストの身柄を確保したそうじゃないか。","ENG":"I saw the report. So you really caught that crazy terrorist this time, eh?","TWN":"我看過報告，聽說你們這次抓到那個瘋狂的恐怖分子？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그래. 지금은 심문을 종결하고 격리시설로 이송 중이다.","JPN":"ああ。今は尋問を終わらせ、隔離施設に移送している。","ENG":"Yes. Her interrogation just finished, and we are transferring her to a quarantined facility.","TWN":"沒錯，現在已經結束審問，正送往隔離中心。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯嗯……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"뭔가 마음에 걸리는 게 있나?","JPN":"何かひっかかることでもあるのか？","ENG":"Is something bothering you?","TWN":"你有哪裡不放心的嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"신병을 확보한 과정이 아무래도 마음에 걸려서.","JPN":"身柄を確保するまでのプロセスが、どうしても気にかかってね。","ENG":"You know, it's just how you caught her that I can't get my mind off of.","TWN":"你們抓到她的過程總讓我覺得不太對勁。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"보고서에는 퍼스트윙이 체포된 계기가 육익 내부에서 일어난 내분 때문이라고 적어 뒀지.","JPN":"報告書にはファーストウイングが逮捕されたきっかけが六翼の内部の抗争にあると書かれていた。","ENG":"The report said that Firstwing was arrested due to the internal conflict caused within Six Wings.","TWN":"報告上說，是因為六翼發生內鬨，你們才得以抓到弗斯特薇。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L30_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만 우리는 내분의 원인이나, 퍼스트윙을 제압한 인물에 대해서는 전달받지 못했어.","JPN":"でも私たちは抗争の原因も、ファーストウイングを制圧した人物についても知らされていない。","ENG":"But we never received any information regarding the cause of the conflict or who was responsible for arresting Firstwing.","TWN":"但內鬨的原因，或是是誰制服弗斯特薇？這些資訊卻一無所知。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"수장도, 그 호위도 클리포트 게임 당시에 출몰했을 텐데.","JPN":"組織のトップも、護衛も、クリフォトゲームのときに出没していたはずなのに。","ENG":"Their leader and his bodyguard both appeared during the Qliphoth Game.","TWN":"不管是帶頭的或是保鑣，應該都曾經出現在逆卡巴拉遊戲中。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 정도로 위험한 인물이 우리 감시망에서 벗어나 있었다는 게 납득이 안 돼.","JPN":"それほどの危険人物が私たちの監視網から漏れていたことが腑に落ちない。","ENG":"And it just doesn't make any sense to me that someone so dangerous was off our radar.","TWN":"這麼危險的人物竟然一直不在我們的監視範圍內，這很令我疑惑。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"과정에서 미심쩍은 부분이 있다는 건 인정하지.","JPN":"プロセスに違和感があるのは認めよう。","ENG":"I admit that there was something suspicious about the process.","TWN":"我承認過程中是存在可疑的部分。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"하지만 퍼스트윙의 신병을 확보한 건 부정할 수 없는 성과야.","JPN":"だが、ファーストウイングの身柄を確保したのは否定できない成果だ。","ENG":"But capturing Firstwing is a definite win that no one can deny.","TWN":"但我們確實有抓到弗斯特薇，這是不可否認的事實。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그 테러리스트가 수용될 교도소는 관리국 최고 보안 레벨의 시설이지.","JPN":"そしてあのテロリストが収監される刑務所は管理局最高のセキュリティレベルを誇る。","ENG":"Also, the prison this terrorist will be locked up in has the highest security level of the Administration.","TWN":"另外，那個恐怖分子收監的監獄，是管理局安全層級最高的地方。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그곳을 탈출하는 건 불가능해.","JPN":"あそこを脱出するのは不可能だ。","ENG":"Escaping that place is impossible.","TWN":"她是不可能從那裡逃跑的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"뭔가 탐탁지 않은 표정이군.","JPN":"まだ腑に落ちないようだな。","ENG":"You don't seem convinced.","TWN":"你的表情很明顯無法接受這個回答。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"궁금한 것이 있다면, 직접 퍼스트윙을 만나서 물어보도록.","JPN":"気になることがあるなら、直接ファーストウイングに会って聞いてみればいい。","ENG":"If you have any questions, ask Firstwing in person.","TWN":"如果你還有什麼想知道的，可以直接去問弗斯特薇。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"이송될 시설 직원에게는 내가 미리 언질해두지.","JPN":"移送先の施設の職員には、私が話をつけておこう。","ENG":"I'll notify the personnel over at the facility beforehand.","TWN":"我會事先通知獄警一聲。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……됐어. 네 일처리를 못 믿는다는 뜻은 아니었으니까.","JPN":"……いや、いい。あなたの仕事ぶりを疑ってのことではないんだ。","ENG":"...Forget it. I didn't mean to say that I didn't trust your competence.","TWN":"……不用，我不是不相信你辦事能力的意思。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그럼 다음 회의 때 보자고, 리하르트.","JPN":"それじゃ次の会議で、リヒャルト。","ENG":"Then, I'll see you again at the next meeting, Richard.","TWN":"那就下次會議時再見吧，理查。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"이야기가 조금 길어졌군. 경기는 어떻게 흘러가고 있지?","JPN":"少し話が長引いてしまったな。試合はどうなっている？","ENG":"That took a little longer than I expected. How is the match going?","TWN":"剛聊得有點久，現在比賽情況如何？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"직접 보시죠.","JPN":"直接ご覧になってください。","ENG":"See for yourself.","TWN":"您親自看看吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"방어 측의 공세가 점점 촘촘해지는 가운데, 카나리아의 곡예 비행은 계속된다……!","JPN":"防御チームの攻撃が勢いを増す中、カナリアは縦横無尽に飛び回る……！","ENG":"The defending team's shots are slowly closing in, but Canary's aerobatics continue...!","TWN":"防守方的攻勢越來越緊湊，金絲雀的特技飛行還在繼續……！"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아! 피격 판정! 하지만 격추 판정까지는 아직 여유가 있다!! 놀라운 스태프의 실력!!","JPN":"あっ！　当たった！　しかし撃墜判定にはなっていない！！　驚くべきスタッフの実力！！","ENG":"Ah! That was a hit! But it's not enough to take it down!! That staff member has some skill!!","TWN":"哎呀！被判定為擊中！但還不至於被判定為擊落！！駕駛員的實力真是驚人！！"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"날개 짓을 멈추지 마, 카나리아─!!","JPN":"羽ばたきを止めるな、カナリア─！！","ENG":"Don't stop flapping your wings, Canary–!","TWN":"繼續振翅高飛，金絲雀—！"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그대로 거점까지 날아가버려!! 여기까지 들어왔으면 이제 후퇴는 불가능 하다구─!!","JPN":"そのまま拠点まで飛んで行け！！　ここまで入り込んだら、もう後戻りはできないぞ─！！","ENG":"Fly straight into their base!! There's no turning back now!!","TWN":"就這樣一舉飛到據點！！已經沒有退路啦—！"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"가라아아아아아아─!!","JPN":"行けえええええ─！！","ENG":"GOOOOO–!!","TWN":"去吧～～～—！！"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"거점까지는 어찌저찌 도달할 수 있을 것 같군요.","JPN":"拠点まではなんとかたどり着けそうですね。","ENG":"It looks as if they will make it to the base, albeit a close call.","TWN":"應該能勉強抵達據點。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"하지만 결국 패배하지 않을까요? 상대가 그 오지만디아스니까요.","JPN":"しかし結局は敗北するのではないでしょうか？　相手はあのオジマンディアスですから。","ENG":"But won't they eventually lose? Their opponent is Ozymandias, after all.","TWN":"但最後還是會輸吧？畢竟對手是奧茲曼迪亞斯。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"글쎄…….","JPN":"どうだろうか……","ENG":"You cannot be so sure...","TWN":"不好說……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"세상에 절대라는 건 없으니까 말이야.","JPN":"世の中に絶対というものはないからな。","ENG":"You see, there are no absolutes in this world.","TWN":"世上沒有什麼事是絕對的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그렇다는 말씀은 시니어님께서는 카나리아 스쿼드가 승리할 거라고 생각하시는 겁니까?","JPN":"ということは、シニアはカナリア・スクワッドが勝利するとお考えなのですか？","ENG":"Then are you saying that you think Canary Squad will win, Senior?","TWN":"您的意思是，您覺得金絲雀小隊會奪冠嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"아마도.","JPN":"おそらく。","ENG":"Perhaps.","TWN":"有機會。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그리고 이번 리그는…….","JPN":"そして今回のリーグは……","ENG":"And this year's league...","TWN":"還有這次的聯賽……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그 여자에게 좋은 본보기가 되겠지.","JPN":"あの女に対する良い見せしめとなるだろう。","ENG":"will make a good example for her.","TWN":"對那個女人來說，會成為好的範本。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};